const body = ($input.item.json && $input.item.json.body) || $input.item.json || {};
if (!body.video_render_id || !body.event_type) return { json: { _bad: true, error: 'video_render_id and event_type required' } };
const valid = ['page_view','video_play','video_25','video_50','video_75','video_complete','cta_click','booking_started','booking_completed','reply_received'];
if (valid.indexOf(body.event_type) < 0) return { json: { _bad: true, error: 'invalid event_type' } };
return { json: { _ok: true, video_render_id: body.video_render_id, event_type: body.event_type, event_data: body.event_data || {} } };

const ctx = $('Validate').item.json;
const rows = $input.item.json;
const review = (Array.isArray(rows) ? rows[0] : rows) || null;
if (!review || !review.id) return { json: { _no_review: true } };
// Map event_type to engagement_status (only upgrade, never downgrade).
const order = ['not_sent','sent','viewed','replied','meeting_booked'];
const current = review.video_engagement_status || 'not_sent';
let next = current;
if (ctx.event_type === 'video_play' || ctx.event_type === 'video_25' || ctx.event_type === 'video_50' || ctx.event_type === 'video_75' || ctx.event_type === 'video_complete' || ctx.event_type === 'page_view') next = 'viewed';
else if (ctx.event_type === 'reply_received' || ctx.event_type === 'cta_click') next = 'replied';
else if (ctx.event_type === 'booking_completed') next = 'meeting_booked';
else if (ctx.event_type === 'booking_started') next = 'replied';
if (order.indexOf(next) < order.indexOf(current)) next = current;
return { json: { policy_review_id: review.id, client_id: review.client_id, advisor_id: review.advisor_id, new_status: next, event_type: ctx.event_type, video_render_id: ctx.video_render_id, event_data: ctx.event_data, status_changed: next !== current } };
